// Busca la sesión del usuario actual, o crea una por defecto
const chatId = $('Extraer Datos Mensaje').first().json.chatId;
const text = $('Extraer Datos Mensaje').first().json.text;
const firstName = $('Extraer Datos Mensaje').first().json.firstName;

const rows = items.map(i => i.json);
let session = rows.find(r => String(r.telegram_user) === String(chatId));

let datosParciales = {};
if (session && session.datos_parciales) {
  try { datosParciales = JSON.parse(session.datos_parciales); } catch (e) { datosParciales = {}; }
}

if (!session) {
  session = {
    telegram_user: chatId,
    pantalla_actual: 'MENU',
    paso_actual: '0',
    datos_parciales: '{}',
    _esNueva: true
  };
}

return [{
  json: {
    chatId,
    text,
    firstName,
    pantalla_actual: session.pantalla_actual || 'MENU',
    paso_actual: session.paso_actual || '0',
    datosParciales,
    esNueva: !!session._esNueva
  }
}];

// Construye el menú numerado de materias a partir de tutores activos
const tutores = items.map(i => i.json).filter(t => (t.estado || '').toLowerCase() === 'activo');
const materiasSet = new Set();
tutores.forEach(t => {
  String(t.especialidad_materias || '').split(',').forEach(m => {
    const materia = m.trim();
    if (materia) materiasSet.add(materia);
  });
});
const materias = Array.from(materiasSet);

let texto = '📚 *Selecciona una materia escribiendo el número:*\n\n';
materias.forEach((m, idx) => {
  texto += `${idx + 1}. ${m}\n`;
});

const chatId = $('Normalizar Sesion').first().json.chatId;

return [{
  json: {
    chatId,
    texto,
    materiasJson: JSON.stringify(materias)
  }
}];

const chatId = $('Normalizar Sesion').first().json.chatId;
const propias = items.map(i => i.json).filter(t => String(t.id_estudiante) === String(chatId));

let texto = '';
if (propias.length === 0) {
  texto = '📭 No tienes tutorías registradas. Usa /solicitar para pedir una.';
} else {
  texto = '📋 *Tus tutorías:*\n\n';
  propias.forEach(t => {
    texto += `🆔 ${t.id_tutoria} | ${t.materia}\n📅 ${t.fecha} 🕐 ${t.hora}\n📌 Estado: *${t.estado}*\n\n`;
  });
}

return [{ json: { chatId, texto } }];

const chatId = $('Normalizar Sesion').first().json.chatId;
const activas = items.map(i => i.json).filter(t => String(t.id_estudiante) === String(chatId) && ['Asignada', 'Confirmada'].includes(t.estado));

let texto = '';
if (activas.length === 0) {
  texto = 'No tienes tutorías activas para cancelar.';
} else {
  texto = '❌ *Responde con el ID de la tutoría que deseas cancelar:*\n\n';
  activas.forEach(t => { texto += `🆔 ${t.id_tutoria} - ${t.materia} (${t.fecha} ${t.hora})\n`; });
}

return [{ json: { chatId, texto, hayActivas: activas.length > 0 } }];

// El usuario escribió un número para elegir materia
const datos = $json.datosParciales || {};
const materias = datos.materiasDisponibles || [];
const opcion = parseInt(($json.text || '').trim(), 10);
const materiaElegida = materias[opcion - 1];

return [{
  json: {
    chatId: $json.chatId,
    materiaElegida: materiaElegida || null,
    valido: !!materiaElegida
  }
}];

// Valida el formato de fecha YYYY-MM-DD y calcula el día de la semana
const chatId = $json.chatId;
const texto = ($json.text || '').trim();
const regex = /^\d{4}-\d{2}-\d{2}$/;
const valido = regex.test(texto) && !isNaN(Date.parse(texto));

let diaSemana = null;
if (valido) {
  const dias = ['Domingo','Lunes','Martes','Miercoles','Jueves','Viernes','Sabado'];
  diaSemana = dias[new Date(texto + 'T00:00:00').getDay()];
}

const datos = $json.datosParciales || {};

return [{ json: { chatId, fecha: texto, diaSemana, valido, materia: datos.materia } }];

// Motor de asignación: cruza materia + tutor activo + disponibilidad libre en el día de la fecha
const validacion = $('Validar Fecha').first().json;
const disponibilidad = $('Leer DISPONIBILIDAD').all().map(i => i.json);
const tutores = $('Leer TUTORES (Match)').all().map(i => i.json);

const tutoresMateria = tutores.filter(t =>
  (t.estado || '').toLowerCase() === 'activo' &&
  String(t.especialidad_materias || '').split(',').map(m => m.trim()).includes(validacion.materia)
);

const idsTutoresValidos = new Set(tutoresMateria.map(t => String(t.id_tutor)));

const slot = disponibilidad.find(d =>
  idsTutoresValidos.has(String(d.id_tutor)) &&
  String(d.dia_semana).toLowerCase() === String(validacion.diaSemana).toLowerCase() &&
  (d.estado || '').toLowerCase() === 'libre'
);

let tutorAsignado = null;
if (slot) {
  tutorAsignado = tutoresMateria.find(t => String(t.id_tutor) === String(slot.id_tutor));
}

return [{
  json: {
    chatId: validacion.chatId,
    materia: validacion.materia,
    fecha: validacion.fecha,
    diaSemana: validacion.diaSemana,
    encontrado: !!(slot && tutorAsignado),
    id_dispo: slot ? slot.id_dispo : null,
    id_tutor: tutorAsignado ? tutorAsignado.id_tutor : null,
    nombreTutor: tutorAsignado ? tutorAsignado.nombre : null,
    horaInicio: slot ? slot.hora_inicio : null,
    horaFin: slot ? slot.hora_fin : null
  }
}];

const chatId = $json.chatId;
const texto = ($json.text || '').trim().toLowerCase();
const datos = $json.datosParciales || {};
const confirmado = texto === 'si' || texto === 'sí';
const rechazado = texto === 'no';

return [{
  json: {
    chatId,
    confirmado,
    rechazado,
    materia: datos.materia,
    fecha: datos.fecha,
    id_dispo: datos.id_dispo,
    id_tutor: datos.id_tutor,
    nombreTutor: datos.nombreTutor,
    horaInicio: datos.horaInicio,
    horaFin: datos.horaFin,
    id_tutoria: 'T-' + Date.now()
  }
}];

